import { Component, OnInit } from '@angular/core';
import { TranslateService } from '@ngx-translate/core';
import { CategoryService, Category } from '../../services/category.service';

type SettingsTab = 'revenue' | 'expense' | 'investment' | 'general';

@Component({
  selector: 'app-settings',
  templateUrl: './settings.component.html',
  styleUrls: ['./settings.component.css']
})
export class SettingsComponent implements OnInit {
  activeTab: SettingsTab = 'revenue';
  categories: Category[] = [];
  filteredCategories: Category[] = [];
  loading = false;
  error: string | null = null;
  successMessage: string | null = null;

  // Form state
  showForm = false;
  editMode = false;
  currentCategory: Partial<Category> = {};

  // Parent categories for hierarchical structure
  parentCategories: Category[] = [];

  // General settings
  generalSettings = {
    ownerSharePercentage: 70,
    partnerSharePercentage: 30,
    defaultCurrency: 'LL',
    exchangeRate: 90000,
    fiscalYearStart: '01-01',
    companyName: 'Funpark',
    companyNameAr: 'فن بارك'
  };

  constructor(
    private categoryService: CategoryService,
    private translate: TranslateService
  ) {}

  ngOnInit(): void {
    this.loadCategories();
    this.loadGeneralSettings();
  }

  loadCategories(): void {
    this.loading = true;
    this.error = null;

    this.categoryService.getAllCategories().subscribe({
      next: (data) => {
        this.categories = data;
        this.filterCategories();
        this.updateParentCategories();
        this.loading = false;
      },
      error: (error) => {
        this.error = this.translate.instant('SETTINGS.MESSAGES.LOAD_ERROR');
        this.loading = false;
        console.error('Error loading categories:', error);
      }
    });
  }

  loadGeneralSettings(): void {
    // Load from localStorage or API
    const saved = localStorage.getItem('generalSettings');
    if (saved) {
      this.generalSettings = JSON.parse(saved);
    }
  }

  saveGeneralSettings(): void {
    localStorage.setItem('generalSettings', JSON.stringify(this.generalSettings));
    this.showSuccessMessage(this.translate.instant('SETTINGS.MESSAGES.SETTINGS_SAVED'));
  }

  filterCategories(): void {
    if (this.activeTab === 'general') {
      this.filteredCategories = [];
      return;
    }

    this.filteredCategories = this.categories.filter(
      cat => cat.type === this.activeTab && cat.is_active === 'true'
    );
  }

  updateParentCategories(): void {
    if (this.activeTab === 'general') {
      this.parentCategories = [];
      return;
    }

    this.parentCategories = this.categories.filter(
      cat => cat.type === this.activeTab && !cat.parent_category && cat.is_active === 'true'
    );
  }

  onTabChange(tab: SettingsTab): void {
    this.activeTab = tab;
    this.filterCategories();
    this.updateParentCategories();
    this.cancelForm();
    this.clearMessages();
  }

  openAddForm(): void {
    this.showForm = true;
    this.editMode = false;
    this.currentCategory = {
      type: this.activeTab as 'revenue' | 'expense' | 'investment',
      name_en: '',
      name_ar: '',
      parent_category: '',
      is_active: 'true'
    };
  }

  openEditForm(category: Category): void {
    this.showForm = true;
    this.editMode = true;
    this.currentCategory = { ...category };
  }

  cancelForm(): void {
    this.showForm = false;
    this.editMode = false;
    this.currentCategory = {};
  }

  saveCategory(): void {
    if (!this.currentCategory.name_en || !this.currentCategory.name_ar) {
      this.showErrorMessage(this.translate.instant('SETTINGS.VALIDATION.NAME_REQUIRED'));
      return;
    }

    this.loading = true;
    this.clearMessages();

    if (this.editMode && this.currentCategory.id) {
      this.categoryService.updateCategory(this.currentCategory.id, this.currentCategory).subscribe({
        next: () => {
          this.showSuccessMessage(this.translate.instant('SETTINGS.MESSAGES.CATEGORY_UPDATED'));
          this.loadCategories();
          this.cancelForm();
        },
        error: (error) => {
          this.showErrorMessage(this.translate.instant('SETTINGS.MESSAGES.UPDATE_ERROR'));
          this.loading = false;
          console.error('Error updating category:', error);
        }
      });
    } else {
      this.categoryService.createCategory(this.currentCategory).subscribe({
        next: () => {
          this.showSuccessMessage(this.translate.instant('SETTINGS.MESSAGES.CATEGORY_CREATED'));
          this.loadCategories();
          this.cancelForm();
        },
        error: (error) => {
          this.showErrorMessage(this.translate.instant('SETTINGS.MESSAGES.CREATE_ERROR'));
          this.loading = false;
          console.error('Error creating category:', error);
        }
      });
    }
  }

  deleteCategory(category: Category): void {
    if (!confirm(this.translate.instant('SETTINGS.DELETE_CONFIRM', { name: this.getCategoryName(category) }))) {
      return;
    }

    this.loading = true;
    this.clearMessages();

    this.categoryService.deleteCategory(category.id).subscribe({
      next: () => {
        this.showSuccessMessage(this.translate.instant('SETTINGS.MESSAGES.CATEGORY_DELETED'));
        this.loadCategories();
      },
      error: (error) => {
        this.showErrorMessage(this.translate.instant('SETTINGS.MESSAGES.DELETE_ERROR'));
        this.loading = false;
        console.error('Error deleting category:', error);
      }
    });
  }

  getCategoryName(category: Category): string {
    const currentLang = this.translate.currentLang;
    return currentLang === 'ar' ? category.name_ar : category.name_en;
  }

  getParentCategoryName(parentName: string): string {
    if (!parentName) return '';
    const parent = this.categories.find(cat => cat.name_en === parentName);
    return parent ? this.getCategoryName(parent) : parentName;
  }

  getChildCategories(parentCategory: Category): Category[] {
    return this.filteredCategories.filter(
      cat => cat.parent_category === parentCategory.name_en
    );
  }

  isParentCategory(category: Category): boolean {
    return !category.parent_category;
  }

  hasChildren(category: Category): boolean {
    return this.getChildCategories(category).length > 0;
  }

  showSuccessMessage(message: string): void {
    this.successMessage = message;
    this.error = null;
    setTimeout(() => {
      this.successMessage = null;
    }, 3000);
  }

  showErrorMessage(message: string): void {
    this.error = message;
    this.successMessage = null;
  }

  clearMessages(): void {
    this.error = null;
    this.successMessage = null;
  }

  getCategoryCount(type: 'revenue' | 'expense' | 'investment'): number {
    return this.categories.filter(cat => cat.type === type && cat.is_active === 'true').length;
  }

  resetToDefaults(): void {
    if (!confirm(this.translate.instant('SETTINGS.RESET_CONFIRM'))) {
      return;
    }

    this.generalSettings = {
      ownerSharePercentage: 70,
      partnerSharePercentage: 30,
      defaultCurrency: 'LL',
      exchangeRate: 90000,
      fiscalYearStart: '01-01',
      companyName: 'Funpark',
      companyNameAr: 'فن بارك'
    };

    this.saveGeneralSettings();
  }
}
<div class="settings-container">
  <div class="header">
    <h1>{{ 'SETTINGS.TITLE' | translate }}</h1>
    <a routerLink="/dashboard" class="btn btn-secondary">{{ 'NAV.DASHBOARD' | translate }}</a>
  </div>

  <div class="settings-content">
    <!-- Tabs -->
    <div class="tabs">
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'revenue'"
        (click)="onTabChange('revenue')">
        <span class="tab-icon">💰</span>
        <span class="tab-text">{{ 'SETTINGS.REVENUE_CATEGORIES' | translate }}</span>
        <span class="tab-count">{{ getCategoryCount('revenue') }}</span>
      </button>
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'expense'"
        (click)="onTabChange('expense')">
        <span class="tab-icon">💸</span>
        <span class="tab-text">{{ 'SETTINGS.EXPENSE_CATEGORIES' | translate }}</span>
        <span class="tab-count">{{ getCategoryCount('expense') }}</span>
      </button>
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'investment'"
        (click)="onTabChange('investment')">
        <span class="tab-icon">📈</span>
        <span class="tab-text">{{ 'SETTINGS.INVESTMENT_TYPES' | translate }}</span>
        <span class="tab-count">{{ getCategoryCount('investment') }}</span>
      </button>
      <button 
        class="tab-button" 
        [class.active]="activeTab === 'general'"
        (click)="onTabChange('general')">
        <span class="tab-icon">⚙️</span>
        <span class="tab-text">{{ 'SETTINGS.GENERAL_SETTINGS' | translate }}</span>
      </button>
    </div>

    <!-- Success Message -->
    <div class="success-message" *ngIf="successMessage">
      ✓ {{ successMessage }}
    </div>

    <!-- Error Message -->
    <div class="error-message" *ngIf="error">
      ✗ {{ error }}
    </div>

    <!-- Loading Indicator -->
    <div class="loading" *ngIf="loading && !showForm">
      {{ 'COMMON.LOADING' | translate }}...
    </div>

    <!-- General Settings Tab -->
    <div class="tab-content" *ngIf="activeTab === 'general' && !loading">
      <div class="general-settings">
        <h2>{{ 'SETTINGS.GENERAL_SETTINGS' | translate }}</h2>

        <div class="settings-section">
          <h3>{{ 'SETTINGS.COMPANY_INFO' | translate }}</h3>

          <div class="form-group">
            <label>{{ 'SETTINGS.COMPANY_NAME' | translate }} (English)</label>
            <input 
              type="text" 
              [(ngModel)]="generalSettings.companyName" 
              class="form-control">
          </div>

          <div class="form-group">
            <label>{{ 'SETTINGS.COMPANY_NAME' | translate }} (العربية)</label>
            <input 
              type="text" 
              [(ngModel)]="generalSettings.companyNameAr" 
              class="form-control"
              dir="rtl">
          </div>
        </div>

        <div class="settings-section">
          <h3>{{ 'SETTINGS.PROFIT_DISTRIBUTION' | translate }}</h3>

          <div class="form-row">
            <div class="form-group">
              <label>{{ 'SETTINGS.FIRST_SHARE_PERCENTAGE' | translate }}</label>
              <div class="input-with-suffix">
                <input 
                  type="number" 
                  [(ngModel)]="generalSettings.ownerSharePercentage" 
                  min="0" 
                  max="100"
                  class="form-control">
                <span class="suffix">%</span>
              </div>
            </div>

            <div class="form-group">
              <label>{{ 'SETTINGS.SECOND_SHARE_PERCENTAGE' | translate }}</label>
              <div class="input-with-suffix">
                <input 
                  type="number" 
                  [(ngModel)]="generalSettings.partnerSharePercentage" 
                  min="0" 
                  max="100"
                  class="form-control">
                <span class="suffix">%</span>
              </div>
            </div>
          </div>

          <div class="info-box" *ngIf="generalSettings.ownerSharePercentage + generalSettings.partnerSharePercentage !== 100">
            ⚠️ {{ 'SETTINGS.PERCENTAGE_WARNING' | translate }}
          </div>
        </div>

        <div class="settings-section">
          <h3>{{ 'SETTINGS.CURRENCY_SETTINGS' | translate }}</h3>

          <div class="form-row">
            <div class="form-group">
              <label>{{ 'SETTINGS.DEFAULT_CURRENCY' | translate }}</label>
              <select [(ngModel)]="generalSettings.defaultCurrency" class="form-control">
                <option value="LL">{{ 'SETTINGS.LEBANESE_POUND' | translate }} (LL)</option>
                <option value="USD">{{ 'SETTINGS.US_DOLLAR' | translate }} (USD)</option>
              </select>
            </div>

            <div class="form-group">
              <label>{{ 'SETTINGS.EXCHANGE_RATE' | translate }} (USD to LL)</label>
              <input 
                type="number" 
                [(ngModel)]="generalSettings.exchangeRate" 
                min="0"
                class="form-control">
            </div>
          </div>
        </div>

        <div class="settings-section">
          <h3>{{ 'SETTINGS.FISCAL_YEAR' | translate }}</h3>

          <div class="form-group">
            <label>{{ 'SETTINGS.FISCAL_YEAR_START' | translate }}</label>
            <input 
              type="text" 
              [(ngModel)]="generalSettings.fiscalYearStart" 
              placeholder="MM-DD"
              class="form-control">
            <small class="form-hint">{{ 'SETTINGS.FISCAL_YEAR_HINT' | translate }}</small>
          </div>
        </div>

        <div class="form-actions">
          <button class="btn btn-primary" (click)="saveGeneralSettings()">
            <span class="icon">💾</span>
            {{ 'COMMON.SAVE' | translate }}
          </button>
          <button class="btn btn-secondary" (click)="resetToDefaults()">
            <span class="icon">🔄</span>
            {{ 'SETTINGS.RESET_DEFAULTS' | translate }}
          </button>
        </div>
      </div>
    </div>

    <!-- Category Management Tabs -->
    <div class="tab-content" *ngIf="activeTab !== 'general' && (!loading || showForm)">

      <!-- Add Button -->
      <div class="action-bar" *ngIf="!showForm">
        <div class="category-stats">
          <span class="stat-item">
            <strong>{{ filteredCategories.length }}</strong> {{ 'SETTINGS.TOTAL_CATEGORIES' | translate }}
          </span>
        </div>
        <button class="btn btn-primary" (click)="openAddForm()">
          <span class="icon">+</span>
          {{ 'SETTINGS.ADD_CATEGORY' | translate }}
        </button>
      </div>

      <!-- Category Form -->
      <div class="category-form" *ngIf="showForm">
        <h3>{{ editMode ? ('SETTINGS.EDIT_CATEGORY' | translate) : ('SETTINGS.ADD_CATEGORY' | translate) }}</h3>

        <div class="form-group">
          <label>{{ 'SETTINGS.ENGLISH_NAME' | translate }} *</label>
          <input 
            type="text" 
            [(ngModel)]="currentCategory.name_en" 
            [placeholder]="'SETTINGS.ENGLISH_NAME_PLACEHOLDER' | translate"
            class="form-control">
        </div>

        <div class="form-group">
          <label>{{ 'SETTINGS.ARABIC_NAME' | translate }} *</label>
          <input 
            type="text" 
            [(ngModel)]="currentCategory.name_ar" 
            [placeholder]="'SETTINGS.ARABIC_NAME_PLACEHOLDER' | translate"
            class="form-control"
            dir="rtl">
        </div>

        <div class="form-group" *ngIf="activeTab === 'expense'">
          <label>{{ 'SETTINGS.PARENT_CATEGORY' | translate }}</label>
          <select [(ngModel)]="currentCategory.parent_category" class="form-control">
            <option value="">{{ 'SETTINGS.NO_PARENT' | translate }}</option>
            <option *ngFor="let parent of parentCategories" [value]="parent.name_en">
              {{ getCategoryName(parent) }}
            </option>
          </select>
          <small class="form-hint">{{ 'SETTINGS.PARENT_CATEGORY_HINT' | translate }}</small>
        </div>

        <div class="form-actions">
          <button class="btn btn-primary" (click)="saveCategory()">
            <span class="icon">💾</span>
            {{ 'COMMON.SAVE' | translate }}
          </button>
          <button class="btn btn-secondary" (click)="cancelForm()">
            {{ 'COMMON.CANCEL' | translate }}
          </button>
        </div>
      </div>

      <!-- Categories List -->
      <div class="categories-list" *ngIf="!showForm">
        <div class="category-group" *ngFor="let category of filteredCategories">
          <div class="category-item" *ngIf="isParentCategory(category)" [class.parent]="true" [class.has-children]="hasChildren(category)">
            <div class="category-info">
              <span class="category-icon">📁</span>
              <span class="category-name">{{ getCategoryName(category) }}</span>
              <span class="category-badge">{{ 'SETTINGS.PARENT' | translate }}</span>
              <span class="children-count" *ngIf="hasChildren(category)">
                {{ getChildCategories(category).length }} {{ 'SETTINGS.SUBCATEGORIES' | translate }}
              </span>
            </div>
            <div class="category-actions">
              <button class="btn-icon edit" (click)="openEditForm(category)" [title]="'COMMON.EDIT' | translate">
                ✏️
              </button>
              <button class="btn-icon delete" (click)="deleteCategory(category)" [title]="'COMMON.DELETE' | translate">
                🗑️
              </button>
            </div>
          </div>

          <!-- Child Categories -->
          <div class="child-categories" *ngIf="isParentCategory(category) && hasChildren(category)">
            <div class="category-item child" *ngFor="let child of getChildCategories(category)">
              <div class="category-info">
                <span class="category-icon">📄</span>
                <span class="category-name">{{ getCategoryName(child) }}</span>
              </div>
              <div class="category-actions">
                <button class="btn-icon edit" (click)="openEditForm(child)" [title]="'COMMON.EDIT' | translate">
                  ✏️
                </button>
                <button class="btn-icon delete" (click)="deleteCategory(child)" [title]="'COMMON.DELETE' | translate">
                  🗑️
                </button>
              </div>
            </div>
          </div>
        </div>

        <!-- Standalone Categories -->
        <div class="category-item standalone" *ngFor="let category of filteredCategories" 
             [hidden]="isParentCategory(category) || category.parent_category">
          <div class="category-info">
            <span class="category-icon">📄</span>
            <span class="category-name">{{ getCategoryName(category) }}</span>
          </div>
          <div class="category-actions">
            <button class="btn-icon edit" (click)="openEditForm(category)" [title]="'COMMON.EDIT' | translate">
              ✏️
            </button>
            <button class="btn-icon delete" (click)="deleteCategory(category)" [title]="'COMMON.DELETE' | translate">
              🗑️
            </button>
          </div>
        </div>

        <div class="no-data" *ngIf="filteredCategories.length === 0">
          <div class="no-data-icon">📭</div>
          <p>{{ 'SETTINGS.NO_CATEGORIES' | translate }}</p>
          <button class="btn btn-primary" (click)="openAddForm()">
            <span class="icon">+</span>
            {{ 'SETTINGS.ADD_FIRST_CATEGORY' | translate }}
          </button>
        </div>
      </div>
    </div>
  </div>
</div>
